import{_ as a,o as s,c as n,a4 as t}from"./chunks/framework.BMymQDdR.js";const m=JSON.parse('{"title":"项目管理器","description":"","frontmatter":{},"headers":[],"relativePath":"v3/designer/Project-Manager.md","filePath":"zh/v3/designer/Project-Manager.md","lastUpdated":1780630099000}'),e={name:"v3/designer/Project-Manager.md"},l=t(`<h1 id="项目管理器" tabindex="-1">项目管理器 <a class="header-anchor" href="#项目管理器" aria-label="Permalink to &quot;项目管理器&quot;">​</a></h1><p>项目管理器位于设计器左侧（组件库右侧），以树形结构展示项目的窗体组件树和源码文件目录。</p><h2 id="界面组成" tabindex="-1">界面组成 <a class="header-anchor" href="#界面组成" aria-label="Permalink to &quot;界面组成&quot;">​</a></h2><p>项目管理器的树形视图包含三个主要节点：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>项目名称/</span></span>
<span class="line"><span>├── Forms/              # 窗体组件树</span></span>
<span class="line"><span>│   ├── Form1           # 窗体根节点</span></span>
<span class="line"><span>│   │   ├── Panel1      # 子组件</span></span>
<span class="line"><span>│   │   │   ├── Button1</span></span>
<span class="line"><span>│   │   │   └── Label1</span></span>
<span class="line"><span>│   │   └── Edit1</span></span>
<span class="line"><span>│   └── Form2</span></span>
<span class="line"><span>│       └── ...</span></span>
<span class="line"><span>└── src/                # 源码文件目录</span></span>
<span class="line"><span>    ├── app/</span></span>
<span class="line"><span>    │   ├── app.go</span></span>
<span class="line"><span>    │   ├── form1.go</span></span>
<span class="line"><span>    │   ├── form1.ui.go</span></span>
<span class="line"><span>    │   └── ...</span></span>
<span class="line"><span>    ├── layouts/</span></span>
<span class="line"><span>    │   ├── form1.ui</span></span>
<span class="line"><span>    │   └── form2.ui</span></span>
<span class="line"><span>    ├── resources/</span></span>
<span class="line"><span>    │   └── ...</span></span>
<span class="line"><span>    ├── main.go</span></span>
<span class="line"><span>    ├── go.mod</span></span>
<span class="line"><span>    └── go.sum</span></span></code></pre></div><h2 id="forms-窗体组件树" tabindex="-1">Forms - 窗体组件树 <a class="header-anchor" href="#forms-窗体组件树" aria-label="Permalink to &quot;Forms - 窗体组件树&quot;">​</a></h2><h3 id="组件树结构" tabindex="-1">组件树结构 <a class="header-anchor" href="#组件树结构" aria-label="Permalink to &quot;组件树结构&quot;">​</a></h3><p>每个窗体作为一棵独立的组件树显示：</p><ul><li>窗体名称为根节点</li><li>放置的组件按层级关系展示</li><li>组件名称显示为 <code>{组件类型}{编号}</code>（如 <code>Button1</code>、<code>Panel2</code>）</li></ul><h3 id="选择组件" tabindex="-1">选择组件 <a class="header-anchor" href="#选择组件" aria-label="Permalink to &quot;选择组件&quot;">​</a></h3><ul><li><strong>单击</strong> 树节点 → 选中该组件，右侧对象检查器同步显示其属性</li><li>选中组件时，设计画布上自动切换到对应的窗体标签页并显示组件的拖拽控制点</li></ul><h3 id="右键菜单" tabindex="-1">右键菜单 <a class="header-anchor" href="#右键菜单" aria-label="Permalink to &quot;右键菜单&quot;">​</a></h3><p>在组件树节点上 <strong>右键</strong> 弹出上下文菜单，支持：</p><table tabindex="0"><thead><tr><th>操作</th><th>说明</th></tr></thead><tbody><tr><td>置顶</td><td>将组件移到最前面（Z 序最前）</td></tr><tr><td>置底</td><td>将组件移到最后面（Z 序最后）</td></tr><tr><td>上移一层</td><td>向前移动一层</td></tr><tr><td>下移一层</td><td>向后移动一层</td></tr><tr><td>删除</td><td>删除选中组件</td></tr></tbody></table><h3 id="组件名管理" tabindex="-1">组件名管理 <a class="header-anchor" href="#组件名管理" aria-label="Permalink to &quot;组件名管理&quot;">​</a></h3><ul><li>组件名称在创建时自动生成，保证唯一性</li><li>组件名称修改时自动检查是否与现有组件重名</li><li>窗体名称修改会联动更新对应的 Go 代码文件中的自引用名称</li></ul><h2 id="src-源码文件目录" tabindex="-1">src - 源码文件目录 <a class="header-anchor" href="#src-源码文件目录" aria-label="Permalink to &quot;src - 源码文件目录&quot;">​</a></h2><h3 id="文件浏览" tabindex="-1">文件浏览 <a class="header-anchor" href="#文件浏览" aria-label="Permalink to &quot;文件浏览&quot;">​</a></h3><p>src 节点显示当前项目的所有源码文件：</p><ul><li><code>app/</code> 目录下的所有文件（窗体代码、UI 代码文件等）</li><li><code>layouts/</code> 目录下的 UI 布局文件（<code>.ui</code> 格式）</li><li><code>resources/</code> 目录下的资源文件（图标、平台元数据等）</li><li>项目根目录下的文件（<code>main.go</code>、<code>go.mod</code>、<code>go.sum</code> 等）</li></ul><h3 id="文件类型标识" tabindex="-1">文件类型标识 <a class="header-anchor" href="#文件类型标识" aria-label="Permalink to &quot;文件类型标识&quot;">​</a></h3><p>不同类型的文件显示不同的图标：</p><ul><li><code>.go</code> 文件 - Go 语言文件图标</li><li><code>.ui</code> 文件 - UI 布局文件图标</li><li><code>.json</code> 文件 - 配置文件图标</li></ul><h3 id="打开文件" tabindex="-1">打开文件 <a class="header-anchor" href="#打开文件" aria-label="Permalink to &quot;打开文件&quot;">​</a></h3><ul><li><strong>双击</strong> 文件节点 → 在代码编辑器中打开该文件</li><li>如果文件属于某个设计窗体，自动切换到对应窗体的子标签页</li><li>非窗体文件在设计器主标签页中以独立编辑器标签打开</li></ul><h2 id="组件树与设计同步" tabindex="-1">组件树与设计同步 <a class="header-anchor" href="#组件树与设计同步" aria-label="Permalink to &quot;组件树与设计同步&quot;">​</a></h2><p>项目管理器的组件树与设计画布保持实时同步：</p><table tabindex="0"><thead><tr><th>操作位置</th><th>同步行为</th></tr></thead><tbody><tr><td>设计画布放置新组件</td><td>组件树中自动添加对应节点</td></tr><tr><td>设计画布选中组件</td><td>组件树中对应节点自动选中</td></tr><tr><td>组件树中选中节点</td><td>设计画布切换到对应窗体并显示选中状态</td></tr><tr><td>删除组件</td><td>组件树中对应节点自动移除</td></tr><tr><td>修改组件属性（如大小、位置）</td><td>组件树节点数据同步更新</td></tr><tr><td>修改窗体名称</td><td>组件树根节点名称同步更新，关联的 Go 代码文件名同步修改</td></tr></tbody></table>`,28),o=[l];function d(r,i,p,c,h,u){return s(),n("div",null,o)}const g=a(e,[["render",d]]);export{m as __pageData,g as default};
